export const ICON_CATALOG = Object.freeze({
  lucide: Object.freeze(Object.values(LUCIDE_CATALOG))
});

export function allIcons() {
  return ICON_CATALOG.lucide;
}

export function iconsForSet(set) {
  return ICON_CATALOG[set] || [];
}

export function filterIcons(entries, searchTerm) {
  if (!Array.isArray(entries)) return [];
  const term = (searchTerm || "").trim().toLowerCase();
  if (!term) return entries;
  return entries.filter(
    (entry) =>
      entry.iconName.toLowerCase().includes(term) ||
      entry.humanLabel.toLowerCase().includes(term)
  );
}

export function findIconByName(iconName) {
  if (!iconName) return null;
  const raw = iconName.trim().toLowerCase().replace(/_/g, "-");
  const unprefixed = raw.includes(":") ? raw.split(":").pop() : raw;
  const normalized =
    LEGACY_ICON_ALIASES[raw] ||
    LEGACY_ICON_ALIASES[unprefixed] ||
    (LUCIDE_CATALOG[unprefixed] ? unprefixed : raw);
  return LUCIDE_CATALOG[normalized] || null;
}
